import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{o as e,c as t,e as r}from"./app.b6fba8d5.js";const o={},i=r('<h1 id="spatial-transformation" tabindex="-1"><a class="header-anchor" href="#spatial-transformation" aria-hidden="true">#</a> Spatial Transformation</h1><p>A portal is a window linking to a transformed space. The spacial transformation can be translation, rotation, scale and mirroring.</p><p>This mod&#39;s teleportation is eye-based. If an entity goes through a portal, it will calculate the entity&#39;s eye position transformed by the portal and then place the entity by the transformed eye position.</p><h2 id="rotation-transformation" tabindex="-1"><a class="header-anchor" href="#rotation-transformation" aria-hidden="true">#</a> Rotation Transformation</h2><p><img src="https://s2.loli.net/2022/04/06/oLOAb38Qe1CNXiS.png" alt="rotation.png"></p><p><a href="./Commands-Reference#rotation">Commands related to rotation</a></p><h3 id="teleportation" tabindex="-1"><a class="header-anchor" href="#teleportation" aria-hidden="true">#</a> Teleportation</h3><p>After crossing a portal with rotation transformation, the player&#39;s camera may be tilted. Then the camera rotation will smoothly turn into a valid state.</p><p>This mod has special compatibility with Gravity Changer mod. With Gravity Changer mod, if you enable <code>teleportChangesGravity</code> to a portal, then your gravity direction will be automatically changed when crossing the portal. (<code>teleportChangesGravity</code> is disabled by default.)</p><h3 id="about-gravity-changer-mod" tabindex="-1"><a class="header-anchor" href="#about-gravity-changer-mod" aria-hidden="true">#</a> About Gravity Changer Mod</h3><p><a href="https://www.curseforge.com/minecraft/mc-mods/gravitychanger" target="_blank" rel="noopener noreferrer">The original Gravity Changer mod by Gaider10 (Andrew)</a>. Gaider10 (Andrew) stopped maintaining it.</p><p>In 1.18.2 you can use <a href="https://github.com/qouteall/GravityChanger/releases/tag/v0.3.1" target="_blank" rel="noopener noreferrer">my fork of Gravity Changer</a> .</p><p>In 1.19, Immersive Portals 2.0.4 is compatible with <a href="https://modrinth.com/mod/gravity-api/version/0.7.12%2Bfabric" target="_blank" rel="noopener noreferrer">Gravity API 0.7.12</a> .</p><h2 id="scale-transformation" tabindex="-1"><a class="header-anchor" href="#scale-transformation" aria-hidden="true">#</a> Scale Transformation</h2><p><img src="https://i.loli.net/2021/11/20/6Y9dimqOSn8NUxA.png" alt="image.png"></p><p><a href="./Commands-Reference#scale">Commands related to scaling</a></p><h3 id="teleportation-1" tabindex="-1"><a class="header-anchor" href="#teleportation-1" aria-hidden="true">#</a> Teleportation</h3><p>This mod has special compatibility with <a href="https://www.curseforge.com/minecraft/mc-mods/pehkui" target="_blank" rel="noopener noreferrer">Pehkui mod</a>. With Pehkui mod, if a player or an entity goes through a portal with scale transformation, it will be scaled. This is controlled by the portal property <code>teleportationChangesScale</code>. (<code>teleportationChangesScale</code> is enabled by default)</p><h2 id="mirror-transformation" tabindex="-1"><a class="header-anchor" href="#mirror-transformation" aria-hidden="true">#</a> Mirror Transformation</h2><p><a href="./Portals#mirrors">Mirrors</a>.</p><h3 id="teleportation-2" tabindex="-1"><a class="header-anchor" href="#teleportation-2" aria-hidden="true">#</a> Teleportation</h3><p>Mirrors do not allow teleportation.</p>',22),n=[i];function s(h,l){return e(),t("div",null,n)}var c=a(o,[["render",s],["__file","Spatial-Transformation.html.vue"]]);export{c as default};
